35.content:
条目:
  key: [Script]系统_区域自动加载(调试版)
  comment: 带弹窗提示的调试版本
  content: |
@@preprocessing
<%_
// 1. 获取位置
if (typeof world === 'undefined') var world = getvar('stat_data.World', { defaults: {} });
var currentLoc = world.Location || "未知";

// 调试弹窗：告诉哥哥当前检测到的位置
toastr.info("📍 当前位置检测: " + currentLoc);

// 2. 圣叶国判定
if (currentLoc.includes('圣叶') || currentLoc.includes('艾克雷西亚') || currentLoc.includes('雪原')) {
// 这里请填入你世界书里真实的条目名！
// 比如你的条目叫 "圣叶国"，就填 "圣叶国"
var targetWiName = '圣叶国艾克雷西亚';

try {
await activewi(null, targetWiName, true);
toastr.success("✅ 已尝试激活: " + targetWiName);
} catch (e) {
toastr.error("❌ 激活失败: 找不到条目 [" + targetWiName + "]");
}
}
_%>

48.content:
@@preprocessing
<%_
  // 1. 获取基础变量 (安全声明)
  if (typeof world === 'undefined') var world = getvar('stat_data.World', { defaults: {} });
  if (typeof player === 'undefined') var player = getvar('stat_data.Player', { defaults: {} });

  // 2. 提取具体属性 (设置默认值)
  var location = world.Location || "未知地点";
  var invasion = world.Invasion || 0;
  var progress = world.Progress || 0;
  var time = world.Time || "未知时间";
  var playerName = player.Name || "你"; // 修复点：增加默认值

  // 3. 确定风格 (根据地点关键词)
  var style = 'wild'; // 默认荒叶国/通用风格
  var paperName = '荒原风声';

  if (location.includes('圣叶') || location.includes('教堂') || location.includes('雪')) {
      style = 'holy';
      paperName = '圣座晨报';
  } else if (location.includes('智叶') || location.includes('法师') || location.includes('塔')) {
      style = 'magic';
      paperName = '真理周刊';
  } else if (location.includes('金叶') || location.includes('商') || location.includes('港')) {
      style = 'gold';
      paperName = '梅尔卡托商报';
  }

  // 4. 生成头版新闻 (优先级: 沦陷 > 攻略完成 > 侵略高 > 攻略高 > 主角)
  var headlineTitle = "边境平静";
  var headlineContent = "今日无事发生，只有风在吹拂。";

  if (invasion >= 90) {
      headlineTitle = "末日警钟：世界沦陷在即！";
      headlineContent = "灾厄领主已突破最后防线，四国联军正在集结。教皇呼吁所有信徒进行最后的祈祷。";
  } else if (progress >= 90) {
      headlineTitle = "黎明将至：魔王城护盾破碎！";
      headlineContent = "勇者联军已攻入神弃之地核心，传说中的轮回即将在今日终结！";
  } else if (invasion >= 50) {
      headlineTitle = "战火蔓延：多地报告魔裔目击";
      headlineContent = "商路受阻，物价飞涨。智叶国贤者议会宣布进入二级战备状态。";
  } else if (progress >= 30) {
      headlineTitle = "新星升起：勇者活动日益频繁";
      headlineContent = `据传闻，一位名为 ${playerName} 的神秘人士在各地展现了非凡的实力。`;
  } else {
      // 随机日常头条
      var randomHeadlines = [
          {t: "回廊法师再次现身？", c: "有目击者称在南部港口看到了传说中的灰袍法师，但他买完鱼就消失了。"},
          {t: "四国贸易协定签署", c: "金叶国与智叶国达成新的魔导器出口协议，预计水晶价格将下跌。"},
          {t: "荒原异动", c: "红土部落的猎人们警告：今年的沙暴比往年更猛烈。"}
      ];
      var rh = randomHeadlines[Math.floor(Math.random() * randomHeadlines.length)];
      headlineTitle = rh.t;
      headlineContent = rh.c;
  }

  // 5. 生成本地新闻 (随机库)
  var localNewsLib = [
      "城东的面包店推出新品'勇者三明治'，据说吃了能增加力量。",
      "下水道又堵了，市政厅正在招募冒险者清理史莱姆。",
      "昨晚有人看到流星划过，占星师称这是吉兆。",
      "铁匠铺打折促销，修复铠甲仅需半价。",
      "一位吟游诗人在酒馆传唱千年前的传说，听众爆满。",
      "最近草药价格上涨，采集任务报酬提升。",
      "警卫队提醒市民夜晚关好门窗，小心盗贼。",
      "某个炼金学徒炸掉了半个实验室，所幸无人伤亡。"
  ];

  // 随机取2条不重复的
  var shuffledNews = localNewsLib.sort(() => 0.5 - Math.random());
  var news1 = shuffledNews[0];
  var news2 = shuffledNews[1];
_%>
<Newspaper>
<Style><%= style %></Style>
<PaperName><%= paperName %></PaperName>
<Date><%= time %></Date>
<Headline>
  <Title><%= headlineTitle %></Title>
  <Content><%= headlineContent %></Content>
</Headline>
<LocalNews>
  <News1><%= news1 %></News1>
  <News2><%= news2 %></News2>
</LocalNews>
</Newspaper>
